'[''整体满意度'', ''性价比'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0236x12000asx1p4q186A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '以前在后面的写字楼上班。这次回来玩住这里特别有亲切感', '以前在后面的写字楼上班。这次回来玩住这里特别有亲切感', '2023-05-02', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232112000b4qhuiu8208_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235v12000b4qhs9tB06D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234s12000b4qhtfn6A6C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236l12000b4qhvui640A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233x12000b4qhzbmF9BD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233m12000b4qhuyyC92A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235v12000b4qhy694C50_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232b12000b4qhyel0FB4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234s12000b4qhvpr4E19_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境好，房间也舒适，有个大浴缸，儿子超喜欢，年三十入住的，超有过年气氛，初一还有', '环境好，房间也舒适，有个大浴缸，儿子超喜欢，年三十入住的，超有过年气氛，初一还有醒狮表演，性价比高，自助早餐品种丰富，晚餐也不错，但价位有点高，胜在方便。', '2023-02-07', 5, '[''性价比'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235512000ama8kf4BD2C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230m12000amabjlzE49C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234612000amaawfx59DA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230o12000amabmoy630C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232b12000amad0t3D866_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235212000amaahz1F72A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231i12000amaa5u2F607_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236y12000amaurn30A8D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230k12000amadb6j426A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不愧为国家首批五星级酒店，接待服务一流！大堂办理入住的 Gillian非常热情，', '不愧为国家首批五星级酒店，接待服务一流！大堂办理入住的 Gillian非常热情，给我们免费升级到套房。设施齐全，卫生整洁，床品舒适，交通方便，小花园环境优美，特别是米其林美食非常好。下次再来广州还住这里。', '2024-05-07', 5, '[''整体满意度'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236412000dwonr182E2A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230912000dwonuvt097E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230612000dwontl83A3F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233k12000dwonvws4D7F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '经常来广州，入住都是选择花园酒店，大堂大气，布置的也非常精美好看，前台同事办理入', '经常来广州，入住都是选择花园酒店，大堂大气，布置的也非常精美好看，前台同事办理入住迅速，房间卫生干净，退房接收到大堂经理lavinia的回访，询问入住体验很贴心。', '2024-07-18', 5, '[''前台服务'', ''卫生状况'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235512000etjvo9t2D15_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常满意，Zoey很热情', '非常满意，Zoey很热情', '2023-05-31', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231h12000bbu9o8b8111_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '整体都很满意，酒店环境服务都很棒，每个服务员都笑意盈盈，时刻打招呼和询问需求，特', '整体都很满意，酒店环境服务都很棒，每个服务员都笑意盈盈，时刻打招呼和询问需求，特别是前台Viria，得知我带父母来游玩，怕老人家舍不得特别给免了加床费，每天的欢迎甜点也很棒，正值中秋还特别准备了小??，唯一美中不足的是酒店手持花洒水温很不稳定，t忽冷忽烫，不知是不是单一间房的问题，老人家洗完澡第二天就感冒发烧了，影响了部分行程，除此之外都挺好', '2023-09-29', 4, '[''房间设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233o12000ca2gdu96686_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236h12000ca2pksn413E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235r12000ca2kupm3356_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '作为80年代建成的第一批酒店，到现在还能吸引网红去打卡，可谓经久不衰。酒店充满岭', '作为80年代建成的第一批酒店，到现在还能吸引网红去打卡，可谓经久不衰。酒店充满岭南特色，园林精致，标志性景点18米双瀑布飞流直下，洞里惊现观音像，博物馆记录了酒店行业发展史，专业布置不输省博。比很多酒店都宽敞的健身房、25米游泳池，自由商务办公区，都非常不错。荔湾亭供应的早餐十分丰富，就是有的点心蒸的时间不够，还可以改善。
6.1儿童节入住，特别感谢前台小姐姐Suki的细心接待，帮考虑了老人小孩的需求，安排了全家都满意的红棉套房。', '2023-06-03', 4, '[''公共设施'', ''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236a12000bcg80fi9E6F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233712000bcgejglF6D7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230m12000bcg3hc37CF4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235612000bcg731z4EAD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235o12000bcg3j2c4159_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231i12000bcg3hc53475_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州花园酒店不愧为中国唯三的白金五星级酒店，1985年开业的酒店到最近的装修，后', '广州花园酒店不愧为中国唯三的白金五星级酒店，1985年开业的酒店到最近的装修，后花园贝大师30年前的设计，现在都不过时。广州的米其林餐厅炳胜公馆、江，味道不错。', '2023-01-23', 5, '[''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236k12000ahq8kd8B5E9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232a12000ahq87as61B8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230q12000ahq7iboB5E1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237212000ahqaz6sE33C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231j12000ahq7uw681FC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235w12000ahqa92g8014_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间特别小 没有淋浴的地方 只能站在浴缸里淋浴 然后就造成了滑倒受伤 挺可怕的 ', '房间特别小 没有淋浴的地方 只能站在浴缸里淋浴 然后就造成了滑倒受伤 挺可怕的 卫生也不好 抽屉里还有用过的浴帽 浴缸里有没清理干净的头发 再也不会住这家酒店了', '2023-01-25', 1, '[''房间设施'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0234912000ai87udu72AD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236j12000ai888mbD544_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231j12000ai88nk24614_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '交通方便，去哪很方便，服务很好，房间设施虽有点陈旧但设计很合理，床超级超级舒服大', '交通方便，去哪很方便，服务很好，房间设施虽有点陈旧但设计很合理，床超级超级舒服大赞！瀑布餐厅人很多感受不好，但二楼荔湾粤式餐厅推荐，环境菜品都很好～下次还来', '2023-01-28', 5, '[''交通便利性'', ''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233v12000aiziw5z119E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233j12000aizkxrc2191_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231k12000aizid3uD1E5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '卫生减一星是杯子没消毒倒水有奇怪甜味', '卫生减一星是杯子没消毒倒水有奇怪甜味
来广州核心区，周边小吃餐厅餐馆众多
楼下还有广式点心和高级西餐日餐厅
服务中规中矩，酒店内花园非常好赞
就是锦鲤进不去，不然就完美了', '2023-01-13', 4, '[''卫生状况'', ''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234t12000afmcb3b82AA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231n12000afmcit91299_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234u12000afmc8i37CCA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234z12000afmcs4x7CCD_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '见过最拥挤的31平米房间 小得放不下两个行李箱 浴室就是一个小浴缸围起来 洗淋浴', '见过最拥挤的31平米房间 小得放不下两个行李箱 浴室就是一个小浴缸围起来 洗淋浴都要跨进浴缸 老人是没办法用的 本来打算住三天 第二天果断退房换酒店', '2023-02-26', 3, '[''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235612000apu4rrq1CC0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', 'rain 服务很好 酒店环境很棒 下次还会再来', 'rain 服务很好 酒店环境很棒 下次还会再来', '2023-05-02', 5, '[''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231i12000b4uowtc7DC7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '64 平的大床房宽敞舒服，基本的服务也在。但花园酒店确实有点老了，前台迎宾接待的', '64 平的大床房宽敞舒服，基本的服务也在。但花园酒店确实有点老了，前台迎宾接待的小姐姐培训不专业。以价位来说不如后面两天住的四季酒店。楼下的荔湾亭餐厅好评，值得一试！', '2023-01-18', 3, '[''房间设施'', ''前台服务'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0231j12000agtjqpmFF42_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '作为广州老字号的星级酒店，真的很不错，有瀑布，有后花园，有酒店博物馆，退房的时候', '作为广州老字号的星级酒店，真的很不错，有瀑布，有后花园，有酒店博物馆，退房的时候人多，又帮我们走快速通道进行办理，总之一切都很好，这次体验很不错', '2023-02-06', 5, '[''公共设施'', ''退房/入住效率'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234c12000alsb0tf26D8_